using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new OrderService();
    }

    #region CreateOrder — Happy Path

    [TestMethod]
    public void CreateOrder_SingleItem_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 9.99m, Quantity = 3 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(29.97m, order.Total);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(1, order.Items.Count);
        Assert.AreEqual("Widget", order.Items[0].ProductName);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_ReturnsSumOfAllItemTotals()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 2 },
            new() { ProductName = "Gadget", Price = 25.50m, Quantity = 1 },
            new() { ProductName = "Doohickey", Price = 5.00m, Quantity = 4 }
        };

        // Act
        var order = _sut.CreateOrder("cust-2", items);

        // Assert — 10*2 + 25.50*1 + 5*4 = 20 + 25.50 + 20 = 65.50
        Assert.AreEqual(65.50m, order.Total);
        Assert.AreEqual(3, order.Items.Count);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_AssignsNonNullId()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_SetsCreatedAtToRecentTime()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };
        var before = DateTime.UtcNow;

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before, $"CreatedAt {order.CreatedAt} should be >= {before}");
        Assert.IsTrue(order.CreatedAt <= after, $"CreatedAt {order.CreatedAt} should be <= {after}");
    }

    [TestMethod]
    public void CreateOrder_ValidInput_StoresOrderForLaterRetrieval()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);
        var retrieved = _sut.GetOrder(order.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreSame(order, retrieved);
    }

    #endregion

    #region CreateOrder — Total Calculation

    [TestMethod]
    [DataRow(1.00, 1, 1.00, DisplayName = "Single unit at $1")]
    [DataRow(7.50, 4, 30.00, DisplayName = "Multiple units")]
    [DataRow(0.01, 1, 0.01, DisplayName = "Penny item")]
    [DataRow(999.99, 10, 9999.90, DisplayName = "Large quantity")]
    public void CreateOrder_SingleItemVariousPricesAndQuantities_CalculatesCorrectTotal(
        double price, int quantity, double expectedTotal)
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Item", Price = (decimal)price, Quantity = quantity }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }

    #endregion

    #region CreateOrder — Error Cases

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };

        // Act & Assert
        var ex = Assert.ThrowsException<ArgumentNullException>(
            () => _sut.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        var ex = Assert.ThrowsException<ArgumentNullException>(
            () => _sut.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItemsList_ThrowsInvalidOperationException()
    {
        // Arrange
        var items = new List<OrderItem>();

        // Act & Assert
        var ex = Assert.ThrowsException<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", items));
        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsCorrectOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 12.00m, Quantity = 1 }
        };
        var created = _sut.CreateOrder("cust-1", items);

        // Act
        var result = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(created.Id, result.Id);
        Assert.AreEqual("cust-1", result.CustomerId);
        Assert.AreEqual(12.00m, result.Total);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        // Act
        var result = _sut.GetOrder("does-not-exist");

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrder_MultipleOrdersExist_ReturnsOnlyRequestedOrder()
    {
        // Arrange
        var items1 = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 1 }
        };
        var items2 = new List<OrderItem>
        {
            new() { ProductName = "Gadget", Price = 20.00m, Quantity = 1 }
        };
        var order1 = _sut.CreateOrder("cust-1", items1);
        var order2 = _sut.CreateOrder("cust-2", items2);

        // Act
        var result = _sut.GetOrder(order2.Id);

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(order2.Id, result.Id);
        Assert.AreEqual(20.00m, result.Total);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_CustomerHasOrders_ReturnsAllCustomerOrders()
    {
        // Arrange
        var items1 = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 1 }
        };
        var items2 = new List<OrderItem>
        {
            new() { ProductName = "Gadget", Price = 20.00m, Quantity = 2 }
        };
        _sut.CreateOrder("cust-1", items1);
        _sut.CreateOrder("cust-1", items2);

        // Act
        var results = _sut.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.AreEqual(2, results.Count);
        Assert.AreEqual(10.00m, results[0].Total);
        Assert.AreEqual(40.00m, results[1].Total);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrdersForCustomer_ReturnsEmptyList()
    {
        // Act
        var results = _sut.GetOrdersByCustomer("unknown-customer");

        // Assert
        Assert.AreEqual(0, results.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MultipleCustomers_ReturnsOnlyRequestedCustomerOrders()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };
        _sut.CreateOrder("cust-1", items);
        _sut.CreateOrder("cust-2", items);
        _sut.CreateOrder("cust-1", items);
        _sut.CreateOrder("cust-3", items);

        // Act
        var results = _sut.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.AreEqual(2, results.Count);
        Assert.IsTrue(results.All(o => o.CustomerId == "cust-1"));
    }

    #endregion
}

